r-id\":\"feq3115\"} -->\n<p [object NamedNodeMap]><em>Por Larissa Vasconcelos</em></p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-social-grp {\"icon_spacing\":\"50\",\"icon_spacing_tablet\":\"35\",\"icon_spacing_mobile\":\"24\",\"icon_size\":\"16\",\"color_scheme\":\"\",\"social_hover\":\"hover\",\"icon_color\":\"#000000ff\",\"icon_color_hover\":\"\",\"social_hover_delay\":\"400\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"qgw1166\"} -->\n<!-- wp:pagelayer/pl-social {\"icon\":\"fab fa-facebook-f\",\"social_url\":\"https://facebook.com/sitepad\",\"pagelayer-id\":\"2088266\",\"tmpAtts\":{\"social_url\":\"https://facebook.com/sitepad\"}} /-->\n\n<!-- wp:pagelayer/pl-social {\"icon\":\"fab fa-instagram\",\"social_url\":\"https://instagram.com/sitepad\",\"pagelayer-id\":\"hri3852\",\"tmpAtts\":{\"social_url\":\"https://instagram.com/sitepad\"}} /-->\n\n<!-- wp:pagelayer/pl-social {\"icon\":\"fab fa-pinterest-p\",\"social_url\":\"https://www.instagram.com/sitepad\",\"pagelayer-id\":\"awn5275\",\"tmpAtts\":{\"social_url\":\"https://www.instagram.com/sitepad\"}} /-->\n<!-- /wp:pagelayer/pl-social-grp -->\n<!-- /wp:pagelayer/pl-col -->\n<!-- /wp:pagelayer/pl-row --></div>\n<!-- /wp:group -->\n\n<!-- wp:pagelayer/pl-row {\"col_gap\":\"10\",\"overlay_hover_delay\":\"400\",\"row_shape_top_width\":\"100\",\"row_shape_top_height\":\"100\",\"row_shape_bottom_width\":\"100\",\"row_shape_bottom_height\":\"100\",\"ele_padding\":\"80px,0px,80px,0px\",\"ele_padding_tablet\":\"50px,0px,50px,0px\",\"ele_padding_mobile\":\"40px,0px,40px,0px\",\"pagelayer-id\":\"2od7242\"} -->\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"overlay_hover_delay\":\"400\",\"pagelayer-id\":\"gu24974\"} -->\n<!-- wp:pagelayer/pl-heading {\"link\":\"\",\"align\":\"center\",\"pagelayer-id\":\"x0i7609\"} -->\n<h2>Alô alô!</h2>\n<!-- /wp:pagelayer/pl-heading -->\n\n<!-- wp:pagelayer/pl-divider {\"divider_color\":\"#fcdca9ff\",\"divider_weight\":\"2\",\"divider_widht\":\"7\",\"divider_gap\":\"10\",\"ele_margin\":\"-15px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"700\",\"pagelayer-id\":\"xk89102\"} /-->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"o3u1437\"} -->\n<p><br></p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"my71363\"} -->\n<p>Um grande diário? Um bloco de notas? Palavras desconexas soltas ao vento? Um pouco de tudo isso sobre a vida na Suécia! Esse blog é um compilado de textos, anotações e dicas escritos ao longo do processo (eterno?) de adaptação, seja em Gotemburgo ou em outro lugar.</p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"mmt1350\"} -->\n<p>Mas antes, deixa eu me apresentar…</p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"ux47067\"} -->\n<p>Eu sou a Larissa Vasconcelos, ou apenas Lalá. Recifense de nascença e criada pelo nordeste, sul, sudeste e centroeste brasileiro. Essas andanças me moldaram e reforçaram aquilo que já fazia parte de mim: uma alma curiosa, que fala pelos cotovelos e na busca pelo meu lugar no mundo.</p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"6wx3498\"} -->\n<p>\n\n\n\n<!-- notionvc: 5f9bd360-d7ab-4dfb-b47c-04961f4d8e95 --></p><p>Jornalista (clichê ou único caminho possível), brinco que a comunicação é parte da minha personalidade, afinal, é uma ferramenta fundamental nessa vida nômade. E sigo buscando formas, lugares e idiomas para me ajudar a lapidar essa arma -nada- secreta</p>\n<!-- /wp:pagelayer/pl-text -->\n<!-- /wp:pagelayer/pl-col -->\n<!-- /wp:pagelayer/pl-row -->\n\n<!-- wp:pagelayer/pl-row {\"col_gap\":\"10\",\"overlay_hover_delay\":\"400\",\"row_shape_top_width\":\"100\",\"row_shape_top_height\":\"100\",\"row_shape_bottom_width\":\"100\",\"row_shape_bottom_height\":\"100\",\"ele_padding\":\"80px,0px,80px,0px\",\"ele_padding_tablet\":\"50px,0px,50px,0px\",\"ele_padding_mobile\":\"40px,0px,40px,0px\",\"pagelayer-id\":\"yjs3655\"} -->\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"overlay_hover_delay\":\"400\",\"pagelayer-id\":\"l627275\"} -->\n<!-- wp:pagelayer/pl-heading {\"link\":\"\",\"align\":\"center\",\"pagelayer-id\":\"zsa4635\"} -->\n<h4>travel</h4>\n<!-- /wp:pagelayer/pl-heading -->\n\n<!-- wp:pagelayer/pl-heading {\"align\":\"center\",\"pagelayer-id\":\"qbi4708\"} -->\n<h3>the places i love </h3>\n<!-- /wp:pagelayer/pl-heading -->\n\n<!-- wp:pagelayer/pl-divider {\"divider_color\":\"#fcdca9ff\",\"divider_weight\":\"2\",\"divider_widht\":\"10\",\"divider_gap\":\"10\",\"ele_margin\":\"-15px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"17n1717\"} /-->\n\n<!-- wp:pagelayer/pl-image {\"id\":\"7\",\"img_hover_delay\":\"400\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"900\",\"pagelayer-id\":\"dbl2454\",\"tmpAtts\":{\"id-full-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/image1.jpg\",\"id-thumbnail-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/image1-150x150.jpg\",\"id-medium-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/image1-300x200.jpg\",\"id-medium_large-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/image1-768x512.jpg\",\"id-large-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/image1-1024x683.jpg\",\"id-1536x1536-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/image1-1536x1024.jpg\",\"id-2048x2048-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/image1.jpg\",\"id-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/image1.jpg\",\"id-alt\":\"image1\",\"id-title\":\"image1\",\"id-link\":\"http://larissabfv.lovestoblog.com/image1/\"}} -->\n<p>Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s.</p>\n<!-- /wp:pagelayer/pl-image -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,14%,0%,14%\",\"ele_padding_tablet\":[\"0px\",\"0px\",\"0px\",\"0px\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"600\",\"pagelayer-id\":\"jkc5099\"} -->\n<p [object NamedNodeMap]>Lorem ipsum dolor sit amet, consectetur adipiscing elit. Proin diam justo, scelerisque non felis porta, placerat vestibulum nisi. Vestibulum ac elementum massa. In rutrum quis risus quis sollicitudin.</p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-divider {\"divider_color\":\"#999999ff\",\"divider_weight\":\"1\",\"divider_widht\":\"100\",\"divider_gap\":\"10\",\"pagelayer-id\":\"lsc3876\"} /-->\n\n<!-- wp:pagelayer/pl-row {\"col_gap\":\"10\",\"overlay_hover_delay\":\"400\",\"row_shape_top_width\":\"100\",\"row_shape_top_height\":\"100\",\"row_shape_bottom_width\":\"100\",\"row_shape_bottom_height\":\"100\",\"pagelayer-id\":\"nfe5391\"} -->\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"col_width\":\"50\",\"overlay_hover_delay\":\"400\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"700\",\"pagelayer-id\":\"elc5814\"} -->\n<!-- wp:pagelayer/pl-heading {\"color\":\"#303030ff\",\"heading_typo\":\"Roboto,14,,500,,,Solid,,,,\",\"pagelayer-id\":\"t1k735\"} -->\n36 views\n<!-- /wp:pagelayer/pl-heading -->\n\n<!-- wp:pagelayer/pl-btn {\"text\":\"Read more\",\"link\":\"#\",\"btn_typo\":\"Cabin,14,,700,,,Solid,1,Uppercase,,\",\"btn_typo_tablet\":\",13,,,,,Solid,,,,\",\"btn_typo_mobile\":\",12,,,,,Solid,,,,\",\"type\":\"pagelayer-btn-custom\",\"size\":\"pagelayer-btn-mini\",\"btn_hover\":\"\",\"btn_bg_color\":\"#00000000\",\"btn_color\":\"#303030ff\",\"btn_hover_delay\":\"400\",\"btn_bg_color_hover\":\"\",\"icon_spacing\":\"5\",\"btn_border_type\":\"solid\",\"btn_border_color\":\"#fcdca9ff\",\"btn_border_width\":\"2,2,2,2\",\"btn_border_radius\":\"0,0,0,0\",\"pagelayer-id\":\"4pt8524\",\"tmpAtts\":{\"link\":\"#\"}} /-->\n<!-- /wp:pagelayer/pl-col -->\n\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"col_width\":\"50\",\"overlay_hover_delay\":\"400\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"vl99904\"} -->\n<!-- wp:pagelayer/pl-heading {\"align\":\"right\",\"color\":\"#303030ff\",\"heading_typo\":\"Roboto,15,,500,,,Solid,,,,\",\"pagelayer-id\":\"br74582\"} -->\nWrite a comment\n<!-- /wp:pagelayer/pl-heading -->\n\n<!-- wp:pagelayer/pl-iconbox {\"service_icon\":\"fas fa-heart\",\"service_alignment\":\"right\",\"service_vertical_alignment\":\"top\",\"service_icon_color\":\"#fe0000ff\",\"service_icon_font_size\":\"18\",\"service_icon_font_size_tablet\":\"16\",\"service_icon_font_size_mobile\":\"14\",\"service_icon_hover_delay\":\"400\",\"service_heading\":\"50\",\"heading_alignment\":\"right\",\"service_title_spacing\":\"0,10,10,0\",\"service_heading_color\":\"#303030ff\",\"service_heading_typo\":\"Cabin,22,,700,,,Solid,,,,\",\"service_heading_typo_tablet\":\",20,,,,,Solid,,,,\",\"service_heading_typo_mobile\":\",18,,,,,Solid,,,,\",\"heading_delay\":\"400\",\"service_btn_hover_delay\":\"400\",\"pagelayer-id\":\"mdx5874\"} -->\nLorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book.\n<!-- /wp:pagelayer/pl-iconbox -->\n<!-- /wp:pagelayer/pl-col -->\n<!-- /wp:pagelayer/pl-row -->\n\n<!-- wp:pagelayer/pl-row {\"col_gap\":\"10\",\"overlay_hover_delay\":\"400\",\"row_shape_top_width\":\"100\",\"row_shape_top_height\":\"100\",\"row_shape_bottom_width\":\"100\",\"row_shape_bottom_height\":\"100\",\"pagelayer-id\":\"1fa6609\"} -->\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"overlay_hover_delay\":\"400\",\"pagelayer-id\":\"sgc3216\"} -->\n<!-- wp:pagelayer/pl-btn {\"text\":\"more post\",\"link\":\"#\",\"btn_typo\":\"Cabin,14,,700,,,Solid,1,Uppercase,,\",\"btn_typo_tablet\":\",13,,,,,Solid,,,,\",\"btn_typo_mobile\":\",12,,,,,Solid,,,,\",\"align\":\"center\",\"type\":\"pagelayer-btn-custom\",\"size\":\"pagelayer-btn-mini\",\"btn_hover\":\"\",\"btn_bg_color\":\"#00000000\",\"btn_color\":\"#303030ff\",\"btn_hover_delay\":\"400\",\"btn_bg_color_hover\":\"\",\"icon_spacing\":\"5\",\"btn_border_type\":\"solid\",\"btn_border_color\":\"#fcdca9ff\",\"btn_border_width\":\"2,2,2,2\",\"btn_border_radius\":\"0,0,0,0\",\"ele_padding\":\"30px,0px,0px,0px\",\"ele_padding_tablet\":\"15px,0px,0px,0px\",\"ele_padding_mobile\":\"15px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"900\",\"pagelayer-id\":\"9184304\",\"tmpAtts\":{\"link\":\"#\"}} /-->\n<!-- /wp:pagelayer/pl-col -->\n<!-- /wp:pagelayer/pl-row -->\n<!-- /wp:pagelayer/pl-col -->\n<!-- /wp:pagelayer/pl-row -->\n\n<!-- wp:pagelayer/pl-row {\"col_gap\":\"10\",\"overlay_hover_delay\":\"400\",\"row_shape_top_width\":\"100\",\"row_shape_top_height\":\"100\",\"row_shape_bottom_width\":\"100\",\"row_shape_bottom_height\":\"100\",\"ele_padding\":\"0px,0px,80px,0px\",\"ele_padding_mobile\":\"0px,0px,40px,0px\",\"pagelayer-id\":\"0x85094\"} -->\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"overlay_hover_delay\":\"400\",\"pagelayer-id\":\"5c95304\"} -->\n<!-- wp:pagelayer/pl-heading {\"link\":\"\",\"align\":\"center\",\"pagelayer-id\":\"ng7961\"} -->\n<h2>About me</h2>\n<!-- /wp:pagelayer/pl-heading -->\n\n<!-- wp:pagelayer/pl-divider {\"divider_color\":\"#fcdca9ff\",\"divider_weight\":\"2\",\"divider_widht\":\"7\",\"divider_gap\":\"10\",\"ele_margin\":\"-15px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"700\",\"pagelayer-id\":\"f247359\"} /-->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"9b64141\"} -->\n<p [object NamedNodeMap]>The truth is: I\'m also knowing myself<br>Well, welcome! As you can notice by the name of my personal blog, I\'m Larissa. I\'m creating this place to write about living abroad, my discoveries and something else I think it\'s interesting. <br>​<br>FAQ:<br>Why in english? <br>Because I wanna practice my skills writing in english, built a portfolio and this is the way I found out.</p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-row {\"col_gap\":\"10\",\"content_pos\":\"center\",\"overlay_hover_delay\":\"400\",\"row_shape_top_width\":\"100\",\"row_shape_top_height\":\"100\",\"row_shape_bottom_width\":\"100\",\"row_shape_bottom_height\":\"100\",\"ele_padding\":\"30px,0px,0px,0px\",\"pagelayer-id\":\"uyk8218\"} -->\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"col_width\":\"50\",\"col_width_tablet\":100,\"col_width_mobile\":\"100\",\"overlay_hover_delay\":\"400\",\"pagelayer-id\":\"spp5808\"} -->\n<!-- wp:pagelayer/pl-heading {\"link\":\"\",\"align\":\"left\",\"heading_typo\":[\"\",\"\",\"\",\"\",\"\",\"\",\"Solid\",\"\",\"Capitalize\",\"\",\"\"],\"pagelayer-id\":\"ynd627\"} -->\n<h2>hello...</h2>\n<!-- /wp:pagelayer/pl-heading -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"3%,0%,0%,0%\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"700\",\"pagelayer-id\":\"lxx2906\"} -->\n<p [object NamedNodeMap]>Acredito que sinceridade e autenticidade são essenciais para prosperar no mundo virtual de hoje. Meu blog é um lugar com a missão de celebrar a personalidade, o senso de humor e o coração. <br><br>Minhas conexão com o mundo foi a motivação para compartilhar minhas vivências aqui. Aos poucos vou preenchendo as páginas com o que me motiva e temas que podem inspirar você também. <br><br>Sugestões e críticas são bem-vindas e estou aberta à novas conexões! </p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"3%,0%,0%,0%\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"700\",\"pagelayer-id\":\"iwe6532\"} -->\n<p><br></p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,0%,0%,0%\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"900\",\"pagelayer-id\":\"eom2183\"} -->\n<p><br></p>\n<!-- /wp:pagelayer/pl-text -->\n<!-- /wp:pagelayer/pl-col -->\n\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"col_width\":\"50\",\"col_width_tablet\":100,\"overlay_hover_delay\":\"400\",\"pagelayer-id\":\"i8y8123\"} -->\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"width\":\"100%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:100%\"><!-- wp:pagelayer/pl-image {\"id\":25,\"align\":\"left\",\"img_hover_delay\":\"400\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"700\",\"pagelayer-id\":\"0qj1390\",\"tmpAtts\":{\"id-full-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/IMG_1608_HEIC.webp\",\"id-thumbnail-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/IMG_1608_HEIC-150x150.webp\",\"id-medium-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/IMG_1608_HEIC-225x300.webp\",\"id-medium_large-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/IMG_1608_HEIC.webp\",\"id-large-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/IMG_1608_HEIC.webp\",\"id-1536x1536-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/IMG_1608_HEIC.webp\",\"id-2048x2048-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/IMG_1608_HEIC.webp\",\"id-url\":\"http://larissabfv.lovestoblog.com/wp-content/uploads/2024/07/IMG_1608_HEIC.webp\",\"id-alt\":\"IMG_1608_HEIC\",\"id-title\":\"IMG_1608_HEIC\",\"id-link\":\"http://larissabfv.lovestoblog.com/home/img_1608_heic/\"}} /--></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:pagelayer/pl-heading {\"link\":\"\",\"align\":\"center\",\"pagelayer-id\":\"pfw1805\"} -->\n<h2>Larissa Vasconcelos   </h2>\n<!-- /wp:pagelayer/pl-heading -->\n<!-- /wp:pagelayer/pl-col -->\n<!-- /wp:pagelayer/pl-row -->\n<!-- /wp:pagelayer/pl-col -->\n<!-- /wp:pagelayer/pl-row -->', 'Home', '', 'inherit', 'closed', 'closed', '', '14-revision-v1', '', '', '2024-08-04 20:16:34', '2024-08-04 20:16:34', '', 14, 'http://larissabfv.lovestoblog.com/?p=57', 0, 'revision', '', 0);
