ê também. <br><br>Sugestões e críticas são bem-vindas e estou aberta à novas conexões! </p>\n<!-- /wp:pagelayer/pl_text -->\n<!-- wp:pagelayer/pl_text {\"ele_padding\":\"3%,0%,0%,0%\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"700\",\"text\":\"\\u003cp\\u003e\\u003cbr\\u003e\\u003c/p\\u003e\",\"ele_bg_gradient\":\"150,#44d3f6,23,#72e584,45,#2ca4eb,100\",\"ele_bg_hover_delay\":400,\"ele_bg_gradient_hover\":\"150,#44d3f6,25,#72e584,75,#2ca4eb,100\",\"border_width\":\"1px,1px,1px,1px\",\"border_color\":\"#CCC\",\"ele_align\":\"margin\",\"ele_height\":\"auto\",\"ele_sticky_on\":\"desktop,tablet,mobile\",\"ele_v_sc_direction\":\"opposite\",\"ele_v_sc_speed\":5,\"ele_v_sc_top_viewport\":100,\"ele_v_sc_bottom_viewport\":100,\"ele_h_sc_direction\":\"toleft\",\"ele_h_sc_speed\":5,\"ele_h_sc_left_viewport\":100,\"ele_h_sc_right_viewport\":100,\"ele_transp_type\":\"fadein\",\"ele_transp_level\":5,\"ele_transp_top_viewport\":100,\"ele_transp_bottom_viewport\":100,\"ele_blur_type\":\"blurin\",\"ele_blur_level\":5,\"ele_blur_top_viewport\":100,\"ele_blur_bottom_viewport\":100,\"ele_rot_direction\":\"clockwise\",\"ele_rot_speed\":5,\"ele_rot_top_viewport\":100,\"ele_rot_bottom_viewport\":100,\"ele_rot_x_anc_point\":\"center\",\"ele_rot_y_anc_point\":\"center\",\"ele_scl_direction\":\"scaleup\",\"ele_scl_level\":5,\"ele_scl_top_viewport\":100,\"ele_scl_bottom_viewport\":100,\"ele_scl_x_anc_point\":\"center\",\"ele_scl_y_anc_point\":\"center\",\"motion_area\":\"viewport\",\"ele_motion_effect_on\":\"desktop,tablet,mobile\",\"ele_m_tr_direction\":\"opposite\",\"ele_m_tr_level\":5,\"ele_3d_tilt_direction\":\"opposite\",\"ele_3d_tilt_level\":5,\"pagelayer-id\":\"iwe6532\"} --><p><br></p><!-- /wp:pagelayer/pl_text -->\n<!-- wp:pagelayer/pl_text {\"ele_padding\":\"0%,0%,0%,0%\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"900\",\"text\":\"\\u003cp\\u003e\\u003cbr\\u003e\\u003c/p\\u003e\",\"ele_bg_gradient\":\"150,#44d3f6,23,#72e584