rt\":100,\"ele_rot_bottom_viewport\":100,\"ele_rot_x_anc_point\":\"center\",\"ele_rot_y_anc_point\":\"center\",\"ele_scl_direction\":\"scaleup\",\"ele_scl_level\":5,\"ele_scl_top_viewport\":100,\"ele_scl_bottom_viewport\":100,\"ele_scl_x_anc_point\":\"center\",\"ele_scl_y_anc_point\":\"center\",\"motion_area\":\"viewport\",\"ele_motion_effect_on\":\"desktop,tablet,mobile\",\"ele_m_tr_direction\":\"opposite\",\"ele_m_tr_level\":5,\"ele_3d_tilt_direction\":\"opposite\",\"ele_3d_tilt_level\":5,\"pagelayer-id\":\"mmt1350\"} -->\n<p>Mas antes, deixa eu me apresentar…</p>\n<!-- /wp:pagelayer/pl_text -->\n<!-- wp:pagelayer/pl_text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":{\"0\":\"0%\",\"1\":\"0%\",\"2\":\"0%\",\"3\":\"0%\"},\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"text\":\"\\n\\u003cp\\u003eEu sou a Larissa Vasconcelos, ou apenas Lalá. Recifense de nascença e criada pelo nordeste, sul, sudeste e centroeste brasileiro. Essas andanças me moldaram e reforçaram aquilo que já fazia parte de mim: uma alma curiosa, que fala pelos cotovelos e na busca pelo meu lugar no mundo.\\u003c/p\\u003e\\n\",\"ele_bg_gradient\":\"150,#44d3f6,23,#72e584,45,#2ca4eb,100\",\"ele_bg_hover_delay\":400,\"ele_bg_gradient_hover\":\"150,#44d3f6,25,#72e584,75,#2ca4eb,100\",\"border_width\":\"1px,1px,1px,1px\",\"border_color\":\"#CCC\",\"ele_align\":\"margin\",\"ele_height\":\"auto\",\"ele_sticky_on\":\"desktop,tablet,mobile\",\"ele_v_sc_direction\":\"opposite\",\"ele_v_sc_speed\":5,\"ele_v_sc_top_viewport\":100,\"ele_v_sc_bottom_viewport\":100,\"ele_h_sc_direction\":\"toleft\",\"ele_h_sc_speed\":5,\"ele_h_sc_left_viewport\":100,\"ele_h_sc_right_viewport\":100,\"ele_transp_type\":\"fadein\",\"ele_transp_level\":5,\"ele_transp_top_viewport\":100,\"ele_transp_bottom_viewport\":100,\"ele_blur_type\":\"blurin\",\"ele_blur_level\":5,\"ele_blur_top_viewport\":100,\"ele_blur_bottom_viewport\":100,\"ele_rot_direction\":\"clockwise\",\"ele_rot_speed\":5,\"ele_rot_top_viewport\":100,\"ele_rot_bottom_viewport\":100,\"ele_rot_x_anc_point\":\"center\",\"ele_rot_y_anc_point\":\"center\",\"ele_scl_direction\":\"scaleup\",\"ele_scl_level\":5,\"ele_scl_top_viewport\":100,\"ele_scl_bottom_viewport\":100,\"ele_scl_x_anc_point\":\"center\",\"ele_scl_y_anc_point\":\"center\",\"motion_area\":\"viewport\",\"ele_motion_effect_on\":\"desktop,tablet,mobile\",\"ele_m_tr_direction\":\"opposite\",\"ele_m_tr_level\":5,\"ele_3d_tilt_direction\":\"opposite\",\"ele_3d_tilt_level\":5,\"pagelayer-id\":\"ux47067\"} -->\n<p>Eu sou a Larissa Vasconcelos, ou apenas Lalá. Recifense de nascença e criada pelo nordeste, sul, sudeste e centroeste brasileiro. Essas andanças me moldaram e reforçaram aquilo que já fazia parte de mim: uma alma curiosa, que fala pelos cotovelos e na busca pelo meu lugar no mundo.</p>\n<!-- /wp:pagelayer/pl_text -->\n<!-- wp:pagelayer/pl_text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":{\"0\":\"0%\",\"1\":\"0%\",\"2\":\"0%\",\"3\":\"0%\"},\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"text\":\"\\n\\u003cp\\u003e\\n\\n\\n\\n\\u003c!\\u002d\\u002d notionvc: 5f9bd360-d7ab-4dfb-b47c-04961f4d8e95 \\u002d\\u002d\\u003e\\u003c/p\\u003e\\u003cp\\u003eJornalista (clichê ou único caminho possível), brinco que a comunicação é parte da minha personalidade, afinal, é uma ferramenta fundamental nessa vida nômade. E sigo buscando formas, lugares e idiomas para me ajudar a lapidar essa arma -nada- secreta\\u003c/p\\u003e\\n\",\"ele_bg_gradient\":\"150,#44d3f6,23,#72e584,45,#2ca4eb,100\",\"ele_bg_hover_delay\":400,\"ele_bg_gradient_hover\":\"150,#44d3f6,25,#72e584,75,#2ca4eb,100\",\"border_width\":\"1px,1px,1px,1px\",\"border_color\":\"#CCC\",\"ele_align\":\"margin\",\"ele_height\":\"auto\",\"ele_sticky_on\":\"desktop,tablet,mobile\",\"ele_v_sc_direction\":\"opposite\",\"ele_v_sc_speed\":5,\"ele_v_sc_top_viewp