pagelayer/pl-row -->\n<!-- /wp:pagelayer/pl-col -->\n<!-- /wp:pagelayer/pl-row -->\n\n<!-- wp:pagelayer/pl-row {\"col_gap\":\"10\",\"overlay_hover_delay\":\"400\",\"row_shape_top_width\":\"100\",\"row_shape_top_height\":\"100\",\"row_shape_bottom_width\":\"100\",\"row_shape_bottom_height\":\"100\",\"ele_padding\":\"0px,0px,80px,0px\",\"ele_padding_mobile\":\"0px,0px,40px,0px\",\"pagelayer-id\":\"0x85094\"} -->\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"overlay_hover_delay\":\"400\",\"pagelayer-id\":\"5c95304\"} -->\n<!-- wp:pagelayer/pl-heading {\"link\":\"\",\"align\":\"center\",\"pagelayer-id\":\"ng7961\"} -->\n<h2>About me</h2>\n<!-- /wp:pagelayer/pl-heading -->\n\n<!-- wp:pagelayer/pl-divider {\"divider_color\":\"#fcdca9ff\",\"divider_weight\":\"2\",\"divider_widht\":\"7\",\"divider_gap\":\"10\",\"ele_margin\":\"-15px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"700\",\"pagelayer-id\":\"f247359\"} /-->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"9b64141\"} -->\n<p [object NamedNodeMap]>The truth is: I\'m also knowing myself<br>Well, welcome! As you can notice by the name of my personal blog, I\'m Larissa. I\'m creating this place to write about living abroad, my discoveries and something else I think it\'s interesting. <br>​<br>FAQ:<br>Why in english? <br>Because I wanna practice my skills writing in english, built a portfolio and this is the way I found out.</p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-row {\"col_gap\":\"10\",\"content_pos\":\"center\",\"overlay_hover_delay\":\"400\",\"row_shape_top_width\":\"100\",\"row_shape_top_height\":\"100\",\"row_shape_bottom_width\":\"100\",\"row_shape_bottom_height\":\"100\",\"ele_padding\":\"30px,0px,0px,0px\",\"pagelayer-id\":\"uyk8218\"} -->\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"col_width\":\"50\",\"col_width_tablet\":100,\"col_width_mobile\":\"100\",\"overlay_hover_delay\":\"400\",\"pagelayer-id\":\"spp5808\"} -->\n<!-- wp:pagelayer/pl-heading {\"link\":\"\",\"align\":\"left\",\"heading_typo\":[\"\",\"\",\"\",\"\",\"\",\"\",\"Solid\",\"\",\"Capitalize\",\"\",\"\"],\"pagelayer-id\":\"ynd627\"} -->\n<h2>hello...</h2>\n<!-- /wp:pagelayer/pl-heading -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"3%,0%,0%,0%\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"700\",\"pagelayer-id\":\"lxx2906\"} -->\n<p [object NamedNodeMap]>Acredito que sinceridade e autenticidade são essenciais para prosperar no mundo virtual de hoje. Meu blog é um lugar com a missão de celebrar a personalidade, o senso de humor e o coração. <br><br>Minhas conexão com o mundo foi a motivação para compartilhar minhas vivências aqui. Aos poucos vou preenchendo as páginas com o que me motiva e temas que podem inspirar você também. <br><br>Sugestões e críticas são bem-vindas e estou aberta à novas conexões! </p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"3%,0%,0%,0%\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"700\",\"pagelayer-id\":\"iwe6532\"} -->\n<p><br></p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,0%,0%,0%\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"900\",\"pagelayer-id\":\"eom2183\"} -->\n<p><br></p>\n<!-- /wp:pagelayer/pl-text -->\n<!-- /wp:pagelayer/pl-col -->\n\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"col_width\":\"50\",\"col_width_tablet\":100,\"overlay_hover_delay\":\"400\",\"pagelayer-id\":\"i8y8123\"} -->\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"width\":\"100%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:100%\"><!-- wp:pagelayer/pl-image {\"id\":25,\"align\":\"left\",\"img_hover_delay\":\"400\"