INSERT INTO `wprp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(71, 1, '2024-08-04 21:35:39', '2024-08-04 21:35:39', '<!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\"></h1>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\" id=\"viewer-bjhjo1121\">Aprovada no mestrado, pedido de casamento, acidente com o Saturno na Bélgica e a impossibilidade de voltar pra casa.</h5>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-lh2ch1123\"><strong>11 de julho - Quinta-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"width\":\"146px\",\"height\":\"auto\",\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft is-resized\"><img src=\"https://static.wixstatic.com/media/1f55df_8da3494def194d26b3ee0ebbb56cec93~mv2.png/v1/fill/w_192,h_251,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_8da3494def194d26b3ee0ebbb56cec93~mv2.png\" alt=\"\" style=\"width:146px;height:auto\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-yqp9i36600\">Nesse dia, eu finalizava uma etapa importante para a minha trajetória profissional, chegava ao fim os 4 meses do <em>praktik </em>(um programa para profissionais conquistarem a primeiro experiência em uma empresa sueca). Ah, mais cedo nesta semana consegui o primeiro trabalho freelancer para uma outra empresa sueca.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-zoruc48307\">Um misto de sentimentos.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"align\":\"right\"} -->\n<figure class=\"wp-block-image alignright\"><img src=\"https://static.wixstatic.com/media/1f55df_91bfd339f6b246d9829872d543099cfd~mv2.png/v1/fill/w_191,h_108,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_91bfd339f6b246d9829872d543099cfd~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-64mdv1127\">E para completar, ainda no dia 11, recebi a aprovação no Mestrado em Comunicação, na Universidade de Gotemburgo!</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-tp9ot48248\">Feliz, ansiosa e aliviada.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-tw8lb1129\"><strong>[12 de julho à 16 de julho - </strong>Finalizando projetos e organizando o carro para uma viagem pela europa acampando no carro<strong>]</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-jof011131\"><strong>17 de julho - Quarta-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-mf34b1133\">Eu, Fefe e Saturno saímos na nossa road-trip de verão, acampando e visitando diferentes cidades na Europa 🐾😎!</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"width\":\"264px\",\"height\":\"auto\",\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft is-resized\"><img src=\"https://static.wixstatic.com/media/1f55df_b5ad153aa3cc40acbbfbc75cd57a3287~mv2.png/v1/fill/w_350,h_212,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_b5ad153aa3cc40acbbfbc75cd57a3287~mv2.png\" alt=\"\" style=\"width:264px;height:auto\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-dnvxl1135\">Os dias que antecederam foram intensos para garantir que estávamos bem preparados comcnossos utensílios, o carro e para garantir que o Saturno estaria confortável — afinal, o verão lá pra baixo está MUITO quente, principalmente para ele que está acostumado com as temperaturas suecas.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-h6t2g1137\">Primeira noite em um rastplats na Dinamarca, tudo muito tranquilo e no dia seguinte seguimos viagem. Estávamos felizes, relaxados e muito empolgados com os próximos dias.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-y1r6c19453\"><strong>18 de julho - Quinta-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"align\":\"right\"} -->\n<figure class=\"wp-block-image alignright\"><img src=\"https://static.wixstatic.com/media/1f55df_13a591e639094e4f83dc86403395156b~mv2.png/v1/fill/w_134,h_170,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_13a591e639094e4f83dc86403395156b~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-cneqo1141\">Já na alemanha, nossa primeira parada foi Rendsburg. A cidadezinha charmosa nos rendeu a primeira sensação de estarmos “fora de casa” e uma leve nostalgia por suas semelhanças com a arquitetura germânica no sul do Brasil.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft\"><img src=\"https://static.wixstatic.com/media/1f55df_7adc5d2ceb344d7aa21d9e2511486acb~mv2.png/v1/fill/w_153,h_233,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_7adc5d2ceb344d7aa21d9e2511486acb~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-opght53630\">Em seguida, Hamburgo tornou-se memorável por sua arquitetura, monumentos e ainda mais pela surpresa que ganhei: <strong><u>O pedido de casamento no monumento de São Nicolau!</u></strong> (Apesar de estarmos juntos há 5 anos, e há quase 2 morando do outro lado do mundo, Fefé sabia o quanto esse gesto era importante para mim).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-26wio1145\">Jantamos, ou melhor, nos empanturramos! E logo em seguida seguimos para um dos melhores resting areas em que já ficamos só pelo chuveirão que eles tinham. E apesar de pagar para TUDO (fazer xixi em euro é sempre triste rs), nós tínhamos um banheiro limpinho e MUITO confortável para tomar banho.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-47bfn1147\"><strong>19 de julho - Sexta-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"align\":\"right\"} -->\n<figure class=\"wp-block-image alignright\"><img src=\"https://static.wixstatic.com/media/1f55df_1b8fca5a4da446ecaeb52512e4a7f849~mv2.png/v1/fill/w_204,h_274,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_1b8fca5a4da446ecaeb52512e4a7f849~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-aj4b81149\">Seguimos viagem para Amsterdã! E me sinto que ainda não processei a beleza e detalhes da capital holandesa. A verdade é que a cidade nos conquistou, de forma inesperada - apesar de quase derreter nosso 🪐 rs. Conhecemos todo o centro, bequinhos, praça e, obviamente, os canais.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-n2dnk64704\">Já estamos pensando em voltar em uma viagem dedicada, bastante tempo e mais liberdade para visitar os museus. Ah, e o mesmo para Rotterdam, cidade pela qual demos uma passeada rápida de carro antes de seguir viagem para a Bélgica.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-6asdj1153\">Assim que cruzamos a fronteira entre Holanda e Bélgica percebemos que não havia área de descanso conforme buscávamos: fora da cidade e perto da estrada.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-jjcnz65104\"><em><u>[Neste ponto as coisas começaram a se complicar um pouquinho]</u></em></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-b83yb65172\">A cidade-destino era a Antuérpia. Ainda fora do centro, próximo ao porto, até achamos uma área de descanso para caminhoneiros inacreditavelmente grande (presenciamos como a sociedade secreta dos motoristas se organiza nas madrugadas haha. Essa história fica para outro momento), e optamos por não nos infiltrar ali rs.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\" id=\"viewer-ichls20842\">Depois de outra tentativa frustrada, passarmos um tempo preenchendo a permissão de entrada na área de baixa emissão para o carro, nós, <em>finalmente</em>, encontramos um um estacionamento de caravanas dentro da cidade. (Detalhe: NENHUM suporte de banheiro ou água potável. Apesar disso, estávamos bem preparados, nosso estoque de água estava cheio e ficamos satisfeitos com a vaga em si). Já passava da meia-noite.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-y0toc1161\"><strong>20 de julho - Sábado</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-6wfq21163\">A noite foi desconfortável para o saturno que ficou com bastante calor (o seu ventiladorzinho</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft\"><img src=\"https://static.wixstatic.com/media/1f55df_28a8dd1cdf234421b138f59f7a42e9ad~mv2.png/v1/fill/w_180,h_229,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_28a8dd1cdf234421b138f59f7a42e9ad~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-wtbiv69140\">dedicado não estava sendo suficiente), eu dormi mal porque ficava de olho nele e logo cedo decidi levantar para que Fefé pudesse descansar mais, afinal, só ele estava dirigindo. Assim, Saturno também descansou ao ar livre com uma brisa fresquinha, já alimentado e hidratado.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-4yrbu1165\">Bom, apesar de tudo isso, <em>decidimos não deixar a peteca cair!</em>&nbsp;Fefé sabia que eu estava mais cansada, era perceptível, e saturno com calor, então decidimos ir com um pouco de calma nesse dia.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"align\":\"right\"} -->\n<figure class=\"wp-block-image alignright\"><img src=\"https://static.wixstatic.com/media/1f55df_621d8fcbb54d49fe840a8e550bce982d~mv2.png/v1/fill/w_278,h_233,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_621d8fcbb54d49fe840a8e550bce982d~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-opcu471511\">Infelizmente, tomamos decisões equivocadas logo no início do passeio e o saturno sofreu um acidente na escada rolante do acesso ao túnel (St. AnnaTunnel) que nos levaria ao centro da Antuérpia.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-zz45u1169\"><em>[Vou adicionar mais detalhes sobre o acidente em outro momento e em outra parte do texto. Ainda nos sentimos muito mal e responsáveis pelo o que aconteceu, mas acho válido o relato para outros tutores de cães, principalmente de grande porte, já que esse é um acidente recorrente no lugar!]</em></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-08a9521637\">Apesar de todo o problema, tivemos MUITA sorte em ter um atendimento veterinário rápido e muito próximo ao local em pleno sábado. O saturno passou por uma pequena cirurgia para fechar o machucado, levou vários pontos na patinha traseira e nós só tinhamos um próximo destino: casa.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-0788n1173\"><strong><em>13 horas, 4 países e muitos quilômetros. E muitos euros a menos…</em></strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-l5b0l1175\">Com o saturno ainda anestesiado no carro, nós só queríamos chegar em casa para que ele pudesse se recuperar o quanto antes e da maneira mais confortável possível. Quase na divisa da Alemanha com a Dinamarca, cerca de 6 horas para alcançar Gotemburgo… Uma falha no motor do carro.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-5hjtd1177\">A primeira noite acampamos no carro, graças a um serviço falho do nosso seguro no exterior.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-q1nz927770\"><strong>21 de julho - Domingo</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft\"><img src=\"https://static.wixstatic.com/media/1f55df_2408c9cc886f40c18369218770398919~mv2.png/v1/fill/w_225,h_180,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_2408c9cc886f40c18369218770398919~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-e5yhb1181\">No dia seguinte, fomos para um hotel na minúscula cidade de Jagel (sem ar-condicionado, sem mercado por perto e 2 possibilidades de restaurantes). Apesar da situação, fomos muito bem atendidos e auxiliados pelo dono do hotel e sua família.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-ip4ht1183\">Além disso, passávamos o tempo livre entre encontrar formas de voltar para casa o mais rápido possível com o Saturno e alternativas para o conserto caríssimo que estaria por vir (o seguro cobre apenas o suporte ao conserto, mas não o conserto em si).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-v69zp28313\"><strong>22 de julho - Segunda-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"align\":\"right\"} -->\n<figure class=\"wp-block-image alignright\"><img src=\"https://static.wixstatic.com/media/1f55df_f02251890fe845e2b0e91b0d1d41f123~mv2.png/v1/fill/w_230,h_254,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_f02251890fe845e2b0e91b0d1d41f123~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-5ja1t1187\">Pegar um avião não era uma possibilidade com o saturno, os ônibus não aceitam cachorros e os trens estavam completamente sem vagas até a semana seguinte (alô alô, olimpíadas). Só nos restou mudar de hotel mais uma vez, dessa vez para a cidade de Kiel (localização perfeita, serviço pet-friendly exemplar) e esperar a saída do próximo navio em direção a Gotemburgo que seria na quarta-feira.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-hu1181189\">Ah, importante citar que a primeira troca de curativo do Saturno também precisava ser feita na segunda-feira sem falta. Graças ao Cadu, um veterinário amigo a quem eu gostaria de dar o mundo por toda a ajuda, compramos novas bandagens, produtos para a limpeza da ferida e instruções sobre como limpar. Uma experiência traumática para todos, mas necessária.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-97uk71191\"><strong>23 de julho - Terça-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-2woob1193\">Esperar, esperar e esperar. Mais uma noite em Kiel já com o nosso ticket em mãos.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-l5rep1195\"><strong>24 de julho - Quarta-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft\"><img src=\"https://static.wixstatic.com/media/1f55df_d3f9357f425b4e23815613e8b9ce7626~mv2.png/v1/fill/w_202,h_254,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_d3f9357f425b4e23815613e8b9ce7626~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-ujihc121742\">Às 14 horas, seguimos para o embarque do navio, há algumas quadras do hotel. Eu lembro de não conseguir sentir alívio nessa volta para casa por puro medo de dar algo errado e eu precisar agir com urgência de novo.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-v998f31267\">Apesar de tudo, no <strong>dia 25</strong>, desembarcamos às 09:30 e chegamos em casa em torno das 10:00.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-lbi391199\">Os problemas não desapareceram só por estarmos na Suécia. O saturno ainda está sendo observado e trocando curativos a cada dois dias, possivelmente precisará passar pelo veterinário em breve porque a recuperação está com complicações; o carro ainda está no conserto na Alemanha, e os gastos com essas emergências estão se saindo bemmmm salgados.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-r6iua31872\"><em>Apesar disso, tudo se torna um pouquinho mais fácil quando estamos em casa, e a vida volta ao seu devido lugar lentamente.</em></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Verão 2024', '', 'inherit', 'closed', 'closed', '', '70-revision-v1', '', '', '2024-08-04 21:35:39', '2024-08-04 21:35:39', '', 70, 'http://larissabfv.lovestoblog.com/?p=71', 0, 'revision', '', 0),
(72, 1, '2024-08-04 21:36:17', '2024-08-04 21:36:17', '<!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">Viagens, conquistas e perrengue</h1>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\" id=\"viewer-bjhjo1121\">Aprovada no mestrado, pedido de casamento, acidente com o Saturno na Bélgica e a impossibilidade de voltar pra casa.</h5>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-lh2ch1123\"><strong>11 de julho - Quinta-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"width\":\"146px\",\"height\":\"auto\",\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft is-resized\"><img src=\"https://static.wixstatic.com/media/1f55df_8da3494def194d26b3ee0ebbb56cec93~mv2.png/v1/fill/w_192,h_251,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_8da3494def194d26b3ee0ebbb56cec93~mv2.png\" alt=\"\" style=\"width:146px;height:auto\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-yqp9i36600\">Nesse dia, eu finalizava uma etapa importante para a minha trajetória profissional, chegava ao fim os 4 meses do <em>praktik </em>(um programa para profissionais conquistarem a primeiro experiência em uma empresa sueca). Ah, mais cedo nesta semana consegui o primeiro trabalho freelancer para uma outra empresa sueca.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-zoruc48307\">Um misto de sentimentos.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"align\":\"right\"} -->\n<figure class=\"wp-block-image alignright\"><img src=\"https://static.wixstatic.com/media/1f55df_91bfd339f6b246d9829872d543099cfd~mv2.png/v1/fill/w_191,h_108,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_91bfd339f6b246d9829872d543099cfd~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-64mdv1127\">E para completar, ainda no dia 11, recebi a aprovação no Mestrado em Comunicação, na Universidade de Gotemburgo!</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-tp9ot48248\">Feliz, ansiosa e aliviada.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-tw8lb1129\"><strong>[12 de julho à 16 de julho - </strong>Finalizando projetos e organizando o carro para uma viagem pela europa acampando no carro<strong>]</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-jof011131\"><strong>17 de julho - Quarta-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-mf34b1133\">Eu, Fefe e Saturno saímos na nossa road-trip de verão, acampando e visitando diferentes cidades na Europa 🐾😎!</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"width\":\"264px\",\"height\":\"auto\",\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft is-resized\"><img src=\"https://static.wixstatic.com/media/1f55df_b5ad153aa3cc40acbbfbc75cd57a3287~mv2.png/v1/fill/w_350,h_212,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_b5ad153aa3cc40acbbfbc75cd57a3287~mv2.png\" alt=\"\" style=\"width:264px;height:auto\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-dnvxl1135\">Os dias que antecederam foram intensos para garantir que estávamos bem preparados comcnossos utensílios, o carro e para garantir que o Saturno estaria confortável — afinal, o verão lá pra baixo está MUITO quente, principalmente para ele que está acostumado com as temperaturas suecas.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-h6t2g1137\">Primeira noite em um rastplats na Dinamarca, tudo muito tranquilo e no dia seguinte seguimos viagem. Estávamos felizes, relaxados e muito empolgados com os próximos dias.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-y1r6c19453\"><strong>18 de julho - Quinta-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"align\":\"right\"} -->\n<figure class=\"wp-block-image alignright\"><img src=\"https://static.wixstatic.com/media/1f55df_13a591e639094e4f83dc86403395156b~mv2.png/v1/fill/w_134,h_170,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_13a591e639094e4f83dc86403395156b~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-cneqo1141\">Já na alemanha, nossa primeira parada foi Rendsburg. A cidadezinha charmosa nos rendeu a primeira sensação de estarmos “fora de casa” e uma leve nostalgia por suas semelhanças com a arquitetura germânica no sul do Brasil.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft\"><img src=\"https://static.wixstatic.com/media/1f55df_7adc5d2ceb344d7aa21d9e2511486acb~mv2.png/v1/fill/w_153,h_233,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_7adc5d2ceb344d7aa21d9e2511486acb~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-opght53630\">Em seguida, Hamburgo tornou-se memorável por sua arquitetura, monumentos e ainda mais pela surpresa que ganhei: <strong><u>O pedido de casamento no monumento de São Nicolau!</u></strong> (Apesar de estarmos juntos há 5 anos, e há quase 2 morando do outro lado do mundo, Fefé sabia o quanto esse gesto era importante para mim).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-26wio1145\">Jantamos, ou melhor, nos empanturramos! E logo em seguida seguimos para um dos melhores resting areas em que já ficamos só pelo chuveirão que eles tinham. E apesar de pagar para TUDO (fazer xixi em euro é sempre triste rs), nós tínhamos um banheiro limpinho e MUITO confortável para tomar banho.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-47bfn1147\"><strong>19 de julho - Sexta-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"align\":\"right\"} -->\n<figure class=\"wp-block-image alignright\"><img src=\"https://static.wixstatic.com/media/1f55df_1b8fca5a4da446ecaeb52512e4a7f849~mv2.png/v1/fill/w_204,h_274,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_1b8fca5a4da446ecaeb52512e4a7f849~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-aj4b81149\">Seguimos viagem para Amsterdã! E me sinto que ainda não processei a beleza e detalhes da capital holandesa. A verdade é que a cidade nos conquistou, de forma inesperada - apesar de quase derreter nosso 🪐 rs. Conhecemos todo o centro, bequinhos, praça e, obviamente, os canais.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-n2dnk64704\">Já estamos pensando em voltar em uma viagem dedicada, bastante tempo e mais liberdade para visitar os museus. Ah, e o mesmo para Rotterdam, cidade pela qual demos uma passeada rápida de carro antes de seguir viagem para a Bélgica.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-6asdj1153\">Assim que cruzamos a fronteira entre Holanda e Bélgica percebemos que não havia área de descanso conforme buscávamos: fora da cidade e perto da estrada.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-jjcnz65104\"><em><u>[Neste ponto as coisas começaram a se complicar um pouquinho]</u></em></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-b83yb65172\">A cidade-destino era a Antuérpia. Ainda fora do centro, próximo ao porto, até achamos uma área de descanso para caminhoneiros inacreditavelmente grande (presenciamos como a sociedade secreta dos motoristas se organiza nas madrugadas haha. Essa história fica para outro momento), e optamos por não nos infiltrar ali rs.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\" id=\"viewer-ichls20842\">Depois de outra tentativa frustrada, passarmos um tempo preenchendo a permissão de entrada na área de baixa emissão para o carro, nós, <em>finalmente</em>, encontramos um um estacionamento de caravanas dentro da cidade. (Detalhe: NENHUM suporte de banheiro ou água potável. Apesar disso, estávamos bem preparados, nosso estoque de água estava cheio e ficamos satisfeitos com a vaga em si). Já passava da meia-noite.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-y0toc1161\"><strong>20 de julho - Sábado</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-6wfq21163\">A noite foi desconfortável para o saturno que ficou com bastante calor (o seu ventiladorzinho</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft\"><img src=\"https://static.wixstatic.com/media/1f55df_28a8dd1cdf234421b138f59f7a42e9ad~mv2.png/v1/fill/w_180,h_229,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_28a8dd1cdf234421b138f59f7a42e9ad~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-wtbiv69140\">dedicado não estava sendo suficiente), eu dormi mal porque ficava de olho nele e logo cedo decidi levantar para que Fefé pudesse descansar mais, afinal, só ele estava dirigindo. Assim, Saturno também descansou ao ar livre com uma brisa fresquinha, já alimentado e hidratado.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-4yrbu1165\">Bom, apesar de tudo isso, <em>decidimos não deixar a peteca cair!</em>&nbsp;Fefé sabia que eu estava mais cansada, era perceptível, e saturno com calor, então decidimos ir com um pouco de calma nesse dia.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"align\":\"right\"} -->\n<figure class=\"wp-block-image alignright\"><img src=\"https://static.wixstatic.com/media/1f55df_621d8fcbb54d49fe840a8e550bce982d~mv2.png/v1/fill/w_278,h_233,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_621d8fcbb54d49fe840a8e550bce982d~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-opcu471511\">Infelizmente, tomamos decisões equivocadas logo no início do passeio e o saturno sofreu um acidente na escada rolante do acesso ao túnel (St. AnnaTunnel) que nos levaria ao centro da Antuérpia.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-zz45u1169\"><em>[Vou adicionar mais detalhes sobre o acidente em outro momento e em outra parte do texto. Ainda nos sentimos muito mal e responsáveis pelo o que aconteceu, mas acho válido o relato para outros tutores de cães, principalmente de grande porte, já que esse é um acidente recorrente no lugar!]</em></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-08a9521637\">Apesar de todo o problema, tivemos MUITA sorte em ter um atendimento veterinário rápido e muito próximo ao local em pleno sábado. O saturno passou por uma pequena cirurgia para fechar o machucado, levou vários pontos na patinha traseira e nós só tinhamos um próximo destino: casa.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-0788n1173\"><strong><em>13 horas, 4 países e muitos quilômetros. E muitos euros a menos…</em></strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-l5b0l1175\">Com o saturno ainda anestesiado no carro, nós só queríamos chegar em casa para que ele pudesse se recuperar o quanto antes e da maneira mais confortável possível. Quase na divisa da Alemanha com a Dinamarca, cerca de 6 horas para alcançar Gotemburgo… Uma falha no motor do carro.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-5hjtd1177\">A primeira noite acampamos no carro, graças a um serviço falho do nosso seguro no exterior.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-q1nz927770\"><strong>21 de julho - Domingo</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft\"><img src=\"https://static.wixstatic.com/media/1f55df_2408c9cc886f40c18369218770398919~mv2.png/v1/fill/w_225,h_180,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_2408c9cc886f40c18369218770398919~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-e5yhb1181\">No dia seguinte, fomos para um hotel na minúscula cidade de Jagel (sem ar-condicionado, sem mercado por perto e 2 possibilidades de restaurantes). Apesar da situação, fomos muito bem atendidos e auxiliados pelo dono do hotel e sua família.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-ip4ht1183\">Além disso, passávamos o tempo livre entre encontrar formas de voltar para casa o mais rápido possível com o Saturno e alternativas para o conserto caríssimo que estaria por vir (o seguro cobre apenas o suporte ao conserto, mas não o conserto em si).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-v69zp28313\"><strong>22 de julho - Segunda-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"align\":\"right\"} -->\n<figure class=\"wp-block-image alignright\"><img src=\"https://static.wixstatic.com/media/1f55df_f02251890fe845e2b0e91b0d1d41f123~mv2.png/v1/fill/w_230,h_254,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_f02251890fe845e2b0e91b0d1d41f123~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-5ja1t1187\">Pegar um avião não era uma possibilidade com o saturno, os ônibus não aceitam cachorros e os trens estavam completamente sem vagas até a semana seguinte (alô alô, olimpíadas). Só nos restou mudar de hotel mais uma vez, dessa vez para a cidade de Kiel (localização perfeita, serviço pet-friendly exemplar) e esperar a saída do próximo navio em direção a Gotemburgo que seria na quarta-feira.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-hu1181189\">Ah, importante citar que a primeira troca de curativo do Saturno também precisava ser feita na segunda-feira sem falta. Graças ao Cadu, um veterinário amigo a quem eu gostaria de dar o mundo por toda a ajuda, compramos novas bandagens, produtos para a limpeza da ferida e instruções sobre como limpar. Uma experiência traumática para todos, mas necessária.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-97uk71191\"><strong>23 de julho - Terça-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-2woob1193\">Esperar, esperar e esperar. Mais uma noite em Kiel já com o nosso ticket em mãos.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":6} -->\n<h6 class=\"wp-block-heading\" id=\"viewer-l5rep1195\"><strong>24 de julho - Quarta-feira</strong></h6>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"align\":\"left\"} -->\n<figure class=\"wp-block-image alignleft\"><img src=\"https://static.wixstatic.com/media/1f55df_d3f9357f425b4e23815613e8b9ce7626~mv2.png/v1/fill/w_202,h_254,al_c,q_85,usm_0.66_1.00_0.01,enc_auto/1f55df_d3f9357f425b4e23815613e8b9ce7626~mv2.png\" alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-ujihc121742\">Às 14 horas, seguimos para o embarque do navio, há algumas quadras do hotel. Eu lembro de não conseguir sentir alívio nessa volta para casa por puro medo de dar algo errado e eu precisar agir com urgência de novo.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-v998f31267\">Apesar de tudo, no <strong>dia 25</strong>, desembarcamos às 09:30 e chegamos em casa em torno das 10:00.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-lbi391199\">Os problemas não desapareceram só por estarmos na Suécia. O saturno ainda está sendo observado e trocando curativos a cada dois dias, possivelmente precisará passar pelo veterinário em breve porque a recuperação está com complicações; o carro ainda está no conserto na Alemanha, e os gastos com essas emergências estão se saindo bemmmm salgados.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p id=\"viewer-r6iua31872\"><em>Apesar disso, tudo se torna um pouquinho mais fácil quando estamos em casa, e a vida volta ao seu devido lugar lentamente.</em></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Verão 2024', '', 'inherit', 'closed', 'closed', '', '70-revision-v1', '', '', '2024-08-04 21:36:17', '2024-08-04 21:36:17', '', 70, 'http://larissabfv.lovestoblog.com/?p=72', 0, 'revision', '', 0),
