logo_img_custom_size\":\"12\",\"logo_img_custom_size_mobile\":\"28\",\"logo_img_custom_size_tablet\":\"14\",\"site_title_style_tablet\":{\"0\":\"\",\"1\":\"\",\"2\":\"\",\"3\":\"\",\"4\":\"\",\"5\":\"\",\"6\":\"Solid\",\"7\":\"\",\"8\":\"\",\"9\":\"\",\"10\":\"\"},\"pagelayer-id\":\"v552465\"} /-->\n<!-- wp:pagelayer/pl_text {\"ele_padding\":\"0%,0%,0%,0%\",\"animation\":\"\",\"animation_delay\":\"700\",\"animation_speed\":\"slowest\",\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"ele_padding_tablet\":\"0px,0px,0px,0px\",\"text\":\"\\u003cp style=\\u0022font-family:roboto;font-size:14px;font-weight:300;line-height:1.5;text-align:left;color:#fff\\u0022\\u003eCompartilho aqui minhas andanças, aprendizados e o que mais der na telha. Ontem, no Brasil. Hoje, na Suécia. Amanhã, nem eu sei.\\u003c/p\\u003e\",\"pagelayer-id\":\"dci3642\"} --><p style=\"font-family:roboto;font-size:14px;font-weight:300;line-height:1.5;text-align:left;color:#fff\">Compartilho aqui minhas andanças, aprendizados e o que mais der na telha. Ontem, no Brasil. Hoje, na Suécia. Amanhã, nem eu sei.</p><!-- /wp:pagelayer/pl_text -->\n<!-- wp:pagelayer/pl_text {\"text\":\"\\u003cp\\u003e\\u003cbr\\u003e\\u003c/p\\u003e\",\"pagelayer-id\":\"ezq9351\"} --><p><br></p><!-- /wp:pagelayer/pl_text -->\n<!-- wp:pagelayer/pl_social_grp {\"align\":\"center\",\"group_layout\":\"pagelayer-btn-grp-horizontal\",\"icon_spacing\":26,\"icon_size\":30,\"color_scheme\":\"\",\"icon_color\":\"#ffffffff\",\"social_hover_delay\":\"400\",\"icon_color_hover\":\"#ffffff\",\"icon_size_mobile\":\"14\",\"icon_spacing_tablet\":\"15\",\"icon_size_tablet\":\"13\",\"bg_shape\":\"pagelayer-social-shape-circle\",\"bg_size\":10,\"icon_bg_color\":\"#0986c0ff\",\"icon_bg_color_hover\":\"#0986c0\",\"pagelayer-id\":\"69a1426\"} -->\n<!-- wp:pagelayer/pl_social {\"icon\":\"fab fa-facebook-f\",\"social_url\":\"https://facebook.com/sitepad\",\"pagelayer-id\":\"wlu9036\"} /-->\n<!-- wp:pagelayer/pl_social {\"icon\":\"fab fa-instagram\",\"social_ur