\",\"icon_spacing_mobile\":\"24\",\"icon_size\":\"16\",\"color_scheme\":\"\",\"social_hover\":\"hover\",\"icon_color\":\"#000000ff\",\"icon_color_hover\":\"\",\"social_hover_delay\":\"400\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"qgw1166\"} -->\n<!-- wp:pagelayer/pl-social {\"icon\":\"fab fa-facebook-f\",\"social_url\":\"https://facebook.com/larii.vasconcelos\",\"pagelayer-id\":\"2088266\",\"tmpAtts\":{\"social_url\":\"https://facebook.com/larii.vasconcelos\"}} /-->\n\n<!-- wp:pagelayer/pl-social {\"icon\":\"fab fa-instagram\",\"social_url\":\"https://instagram.com/lariivasconcelos\",\"pagelayer-id\":\"hri3852\",\"tmpAtts\":{\"social_url\":\"https://instagram.com/lariivasconcelos\"}} /-->\n\n<!-- wp:pagelayer/pl-social {\"icon\":\"fab fa-pinterest-p\",\"social_url\":\"https://www.instagram.com/sitepad\",\"pagelayer-id\":\"awn5275\",\"tmpAtts\":{\"social_url\":\"https://www.instagram.com/sitepad\"}} /-->\n<!-- /wp:pagelayer/pl-social-grp -->\n<!-- /wp:pagelayer/pl-col -->\n<!-- /wp:pagelayer/pl-row --></div>\n<!-- /wp:group -->\n\n<!-- wp:pagelayer/pl-row {\"col_gap\":\"10\",\"overlay_hover_delay\":\"400\",\"row_shape_top_width\":\"100\",\"row_shape_top_height\":\"100\",\"row_shape_bottom_width\":\"100\",\"row_shape_bottom_height\":\"100\",\"ele_padding\":\"80px,0px,80px,0px\",\"ele_padding_tablet\":\"50px,0px,50px,0px\",\"ele_padding_mobile\":\"40px,0px,40px,0px\",\"pagelayer-id\":\"2od7242\"} -->\n<!-- wp:pagelayer/pl-col {\"widget_space\":\"15\",\"col\":6,\"col_width\":\"\",\"overlay_hover_delay\":\"400\",\"pagelayer-id\":\"gu24974\"} -->\n<!-- wp:pagelayer/pl-heading {\"link\":\"\",\"align\":\"center\",\"pagelayer-id\":\"x0i7609\"} -->\n<h2>Alô alô!</h2>\n<!-- /wp:pagelayer/pl-heading -->\n\n<!-- wp:pagelayer/pl-divider {\"divider_color\":\"#fcdca9ff\",\"divider_weight\":\"2\",\"divider_widht\":\"7\",\"divider_gap\":\"10\",\"ele_margin\":\"-15px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"700\",\"pagelayer-id\":\"xk89102\"} /-->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"o3u1437\"} -->\n<p><br></p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"my71363\"} -->\n<p>Um grande diário? Um bloco de notas? Palavras desconexas soltas ao vento? <br><br>Um pouco de tudo isso sobre uma vida de mudanças, agora na Suécia. Esse blog é um compilado de textos, anotações e dicas escritos ao longo do processo (eterno?) de adaptação, seja em Gotemburgo ou em outro lugar.</p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"mmt1350\"} -->\n<p><em>Mas antes, deixa eu me apresentar…</em></p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"ux47067\"} -->\n<p>Eu sou a Larissa Vasconcelos, ou apenas Lalá. Recifense de nascença e criada pelo nordeste, sul, sudeste e centroeste brasileiro. Essas andanças me moldaram e reforçaram aquilo que já fazia parte de mim: uma alma curiosa, que fala pelos cotovelos e em busca pelo meu lugar no mundo.</p>\n<!-- /wp:pagelayer/pl-text -->\n\n<!-- wp:pagelayer/pl-text {\"ele_padding\":\"0%,24%,0%,24%\",\"ele_padding_tablet\":[\"0%\",\"0%\",\"0%\",\"0%\"],\"ele_padding_mobile\":\"0px,0px,0px,0px\",\"animation\":\"\",\"animation_speed\":\"slowest\",\"animation_delay\":\"800\",\"pagelayer-id\":\"6wx3498\"} -->\n<p>Também sou Jornalista -<em>clichê ou único caminho possível?</em>-, e brinco que a comunicação é parte da minha personalidade, afinal, é uma ferramenta fundamental nessa vida nômade. <br><br>É com base nisso tudo que nasceu o \"Lá por aí\"!</p>\n<!-- /wp:pagelayer/pl-text -->\n<!-- /wp:pagelayer/pl-col -->\n<!-- /wp:pagelayer/pl-row -->\n\n<!-- wp:pagelayer/pl-row {\"pagelayer-id\":\"7is233\"} -->\n<!-- wp:pagelayer/pl-col {\"pagelayer-id\":\"b2f3100\"} -->\n<!-- wp:query {\"queryId\":17,\"query\":{\"perPage\":3,\"pages\":0,\"offset\":0,\"postType\":\"post\",\"order\":\"desc\",\"orderBy\":\"date\",\"author\":\"\",\"search\":\"\",\"exclude\":[],\"sticky\":\"\",\"inherit\":false},\"metadata\":{\"categories\":[\"posts\"],\"patternName\":\"core/query-standard-posts\",\"name\":\"Padrão\"}} -->\n<div class=\"wp-block-query\"><!-- wp:post-template -->\n<!-- wp:post-title {\"isLink\":true} /-->\n\n<!-- wp:post-featured-image {\"isLink\":true,\"align\":\"wide\"} /-->\n\n<!-- wp:post-excerpt /-->\n\n<!-- wp:separator {\"opacity\":\"css\"} -->\n<hr class=\"wp-block-separator has-css-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:post-date /-->\n<!-- /wp:post-template --></div>\n<!-- /wp:query -->\n<!-- /wp:pagelayer/pl-col -->\n<!-- /wp:pagelayer/pl-row -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Home', '', 'inherit', 'closed', 'closed', '', '14-revision-v1', '', '', '2024-08-09 10:36:12', '2024-08-09 10:36:12', '', 14, 'http://laporai.com/?p=133', 0, 'revision', '', 0);
